#!/usr/bin/env node
/**
 * expand-livestock-feed.js
 * Adds unique SEO content sections to all 15 livestock feed country pages.
 * Inserts after </main> and before <afro-footer>.
 */
const fs = require('fs');
const path = require('path');

const DIR = path.join(__dirname, '..', 'agriculture', 'livestock-feed');

const DATA = {
  angola: {
    name: 'Angola',
    overview: 'Angola\'s livestock sector is rebuilding after decades of civil conflict, with cattle, goats, pigs, and poultry as the primary livestock types. The southern provinces of Huila, Cunene, and Namibe support the largest cattle herds, while pigs and poultry are raised across the central highlands and peri-urban areas around Luanda. The feed industry is still nascent, with most smallholder livestock keepers relying on natural pastures and crop residues rather than commercial feed. Imported feed ingredients and finished feeds are expensive due to Angola\'s import-dependent economy and logistics challenges. The government\'s agricultural diversification strategy includes livestock development as a priority, aiming to reduce the country\'s heavy reliance on imported meat and dairy products. Commercial poultry operations around Luanda represent the most advanced segment of the feed industry, with several large-scale operations importing pre-mixed feeds or raw ingredients for on-site formulation.',
    ingredients: 'Angola\'s livestock feed landscape relies heavily on locally available crop byproducts and natural forages. Cassava peels and chips are among the most abundant energy sources, given that cassava is the country\'s staple food crop, and dried cassava meal can replace up to 40% of maize in poultry and pig diets. Maize bran and broken maize grains from the central highlands provide supplementary energy. Groundnut cake from groundnut processing in the Huambo and Malanje provinces offers a valuable protein source. Cottonseed cake is available in limited quantities from cotton-growing areas. For ruminants, natural pastures of Hyparrhenia and Brachiaria grasses in the southern provinces provide the grazing base, supplemented by crop residues including maize stover, bean haulms, and sorghum stalks after harvest. Leucaena and Gliricidia leaves from planted fodder trees provide protein-rich browse for cattle and goats. Palm kernel cake from oil palm processing in the northern provinces is an underutilized but potentially significant feed ingredient. Fish meal from Angola\'s productive Atlantic fisheries is available but expensive and primarily directed to the poultry sector.',
    cost: 'Feed costs in Angola are significantly higher than in most African countries due to the heavy dependence on imports and logistical challenges of internal distribution. Farmers near Luanda and other major cities have better access to commercial feed suppliers and imported ingredients, while those in remote provinces face severe supply constraints. Seasonal price variations are pronounced, with feed ingredients becoming most expensive during the dry season (May to September) when natural pastures decline and demand for supplementary feeds peaks. Cost-saving strategies include maximizing the use of locally available crop byproducts, establishing small-scale feed mixing operations at the farm or community level, and cultivating improved forages such as Brachiaria brizantha and Panicum maximum during the rainy season for conservation as hay or silage. Poultry farmers around Luanda have formed purchasing cooperatives to negotiate bulk prices on imported soybean meal and maize. The government\'s investment in local feed mills and the promotion of drought-tolerant forage species in the southern pastoral zones are expected to gradually improve feed availability and reduce costs for Angolan livestock producers.'
  },
  cameroon: {
    name: 'Cameroon',
    overview: 'Cameroon has one of Central Africa\'s most diverse livestock sectors, spanning the pastoral Sahelian north (where Fulani herders raise Zebu cattle, sheep, and goats), the Guinea savanna (mixed crop-livestock systems), and the humid south and west (intensive poultry and pig production). The country has approximately 6 million cattle, over 7 million goats, 4 million sheep, and a rapidly growing poultry sector. The commercial feed industry is centered in Douala and Yaounde, with several feed mills (including Sanders Cameroun, SPC, and local operators) producing compound feeds primarily for the booming poultry sector. The northern pastoral zone relies almost entirely on natural rangelands managed through transhumance systems. Cameroon\'s agricultural diversity provides a wide range of potential feed ingredients, though the feed industry competes with human food demand for key commodities like maize and soybean.',
    ingredients: 'Cameroon benefits from a diverse range of locally available feed ingredients across its varied agroecological zones. Maize is the primary energy source in commercial poultry and pig feeds, grown extensively in the North-West, West, and Adamawa regions. Cottonseed cake from SODECOTON\'s ginneries in the Far North and North regions is a major protein source, widely used in ruminant and pig feeding. Soybean meal from expanding soybean production in the Adamawa and North-West regions is increasingly available for poultry feeds. Groundnut cake and sesame cake provide additional protein options. Palm kernel cake from the oil palm industry in the Littoral and South-West regions is an economical energy and fiber source for ruminants. Brewers\' dried grain (BDG) from the beer industry (SABC/Guinness) in Douala and Yaounde is a sought-after ingredient for dairy cattle. For ruminants, Brachiaria ruziziensis, Pennisetum purpureum (Napier grass), and natural savanna grasses provide the forage base. Leucaena leucocephala and Calliandra calothyrsus fodder trees are promoted in the Western Highlands for dairy goat and cattle feeding. Fish meal from artisanal fisheries on the coast and Lake Chad provides essential amino acids for poultry diets.',
    cost: 'Feed represents 60 to 70% of production costs in Cameroon\'s commercial poultry and pig sectors, making cost management critical for profitability. Maize prices fluctuate significantly between the post-harvest period (October to December, when prices are lowest) and the lean season (July to September, when prices peak at up to 50% above harvest-time levels). Farmers can reduce costs by purchasing and storing maize immediately after harvest, establishing on-farm feed mixing operations to avoid commercial feed mill margins, and maximizing the inclusion of cheaper local ingredients like cassava meal, palm kernel cake, and cottonseed cake. The northern pastoral zone offers some of the most affordable ruminant feeding, with natural pastures providing the bulk of nutrition during the rainy season, supplemented by cotton seed and groundnut haulm purchased cheaply at local markets during the dry season. For dairy farmers in the North-West and Western Highlands, establishing improved Brachiaria and Napier grass pastures can dramatically reduce purchased feed costs. Feed ingredient traders operate at the major markets in Douala, Yaounde, Bafoussam, and Garoua, and farmers benefit from buying through cooperatives that can negotiate bulk discounts and arrange transport from producing regions.'
  },
  'cote-d-ivoire': {
    name: 'Cote d\'Ivoire',
    overview: 'Cote d\'Ivoire\'s livestock sector is growing rapidly, driven by urbanization and increasing demand for meat, eggs, and dairy products. The northern savanna zones support cattle and small ruminant production, while poultry and pig farming are concentrated in the peri-urban areas around Abidjan, Bouake, and other major cities. The country imports a significant share of its meat consumption, creating opportunities for domestic livestock expansion. The commercial poultry sector has expanded substantially, with modern broiler and layer operations around Abidjan supported by a growing feed milling industry including SIPRA, ALCI, and Ivoire Grain. The pastoral north faces challenges of seasonal feed scarcity, transhumance conflicts with crop farmers, and limited access to veterinary services. The government\'s National Livestock Development Program (PNDEL) aims to boost domestic meat and egg production to reduce imports.',
    ingredients: 'Cote d\'Ivoire offers a range of locally available feed ingredients leveraging its strong agricultural base. Maize is the primary energy component in commercial poultry and pig feeds, sourced from the central and northern production zones. Copra (coconut) cake and palm kernel cake from the coconut and oil palm industries in the coastal and southern zones provide economical energy and moderate protein for ruminant and pig diets. Cottonseed cake from the northern cotton zone (COIC companies) is a key protein source for livestock across the country. Soybean is increasingly cultivated in the central regions, providing domestic soybean meal for the feed industry. Cashew nut shell cake, a byproduct of the growing cashew processing industry, is being explored as a feed ingredient. For ruminants in the north, Andropogon and Hyparrhenia natural grasses form the grazing base, supplemented by Stylosanthes guianensis and Panicum maximum planted forages. Crop residues including rice straw, maize stover, and groundnut haulms are important dry season feeds. Cocoa pod husks, abundantly available from the country\'s massive cocoa industry, can be processed and used as a roughage source for ruminants, though their theobromine content requires careful management.',
    cost: 'Feed costs in Cote d\'Ivoire\'s livestock sector are influenced by competition between animal feed and human food uses for key crops like maize, and by the seasonal dynamics of crop byproduct availability. The commercial poultry sector around Abidjan faces high maize costs when domestic supplies tighten, leading some operators to supplement with imported maize or substitute with cassava-based energy sources. Purchasing strategies that exploit post-harvest price dips (November to January for maize) can save 20 to 30% on annual feed costs. Palm kernel cake and cottonseed cake offer cost-effective protein-energy alternatives that are typically cheaper than soybean meal. Livestock farmers in the north benefit from lower land costs and abundant natural forage during the rainy season, but face sharply rising feed costs during the dry months (November to April) when pastures dry out and supplementary feeding becomes necessary. Establishing forage banks of Brachiaria and Stylosanthes, and conserving crop residues through proper storage, are practical dry-season strategies. Feed ingredient markets operate at Abobo, Adjame, and Port-Bouet in the Abidjan area, and at Korhogo and Bouake markets in the north and center. Cooperative purchasing arrangements help smaller poultry and pig farmers access ingredients at bulk pricing.'
  },
  egypt: {
    name: 'Egypt',
    overview: 'Egypt has the most intensive and industrialized livestock sector in Africa, with large-scale dairy, poultry, and aquaculture operations alongside traditional cattle fattening and small ruminant production. The country\'s livestock sector is concentrated in the Nile Delta and Valley, with major poultry companies (including Cairo Poultry Group, Wadi Food, and ElKabier) operating integrated operations. Egypt is Africa\'s largest dairy producer, with a mix of small-scale buffalo and cattle dairy farms and modern commercial operations. The feed industry is well-developed, with numerous feed mills across the Delta and Upper Egypt producing compound feeds for poultry, dairy, aquaculture, and other livestock. Egypt imports significant quantities of feed ingredients, particularly maize, soybean meal, and fishmeal, making the sector vulnerable to international commodity price fluctuations. The aquaculture industry, centered in the Delta lakes and desert reclamation areas, is one of Africa\'s largest and a significant consumer of specialized fish feeds.',
    ingredients: 'Egypt\'s feed ingredient base combines domestic production with substantial imports. Maize (locally grown and imported) is the primary energy source, supplemented by wheat bran from the country\'s enormous wheat milling industry. Soybean meal is the dominant protein source for poultry and aquaculture, almost entirely imported from the Americas. Cottonseed meal from Egypt\'s significant cotton industry provides a cost-effective protein option for ruminants. Berseem (Egyptian clover), the traditional winter forage, is one of the most important locally produced feed resources, providing high-quality green feed and hay for dairy cattle and buffalo from October through May. Rice straw from the Delta rice fields is abundantly available but has low nutritional value without treatment (urea treatment is commonly practiced to improve digestibility). Sugarcane bagasse and molasses from the Upper Egypt sugar industry provide energy supplements. Corn gluten meal is produced by wet milling operations. For aquaculture, locally produced fish meal from Lake Nasser and the Mediterranean, along with imported soybean meal and fish meal, form the protein base. Dried Distillers Grains with Solubles (DDGS) are increasingly imported as an alternative protein-energy ingredient for dairy and beef cattle.',
    cost: 'Feed costs represent the largest single expense in Egyptian livestock production, typically accounting for 65 to 75% of total costs in poultry and aquaculture operations. Prices are heavily influenced by international commodity markets, with maize and soybean meal imports subject to exchange rate fluctuations and global supply dynamics. Farmers and feed millers manage costs by maintaining strategic stocks of imported ingredients when prices are favorable, typically during the post-harvest periods in major exporting countries (October to December for US corn and soybeans). The availability of berseem clover during winter months (October to May) significantly reduces feed costs for dairy and cattle operations during that period. Rice straw, though low quality, is extremely cheap during the October-November harvest and can be treated with urea to create an acceptable roughage at a fraction of berseem cost. Commercial feed producers operate throughout the Delta cities (Tanta, Mansura, Zagazig) and in Cairo and Upper Egypt (Minya, Assiut). Smaller livestock operations can reduce costs by purchasing ingredients from local wholesale markets and using simple on-farm mixing equipment. The government periodically intervenes in feed ingredient markets to stabilize prices, and the General Organization for Veterinary Services (GOVS) monitors feed quality and safety across the supply chain.'
  },
  ethiopia: {
    name: 'Ethiopia',
    overview: 'Ethiopia has Africa\'s largest livestock population, with approximately 70 million cattle, 42 million sheep, 52 million goats, and a rapidly growing poultry sector. Livestock contributes significantly to the economy and is central to livelihoods in the pastoral lowlands (Somali, Afar, Borana regions) and the mixed crop-livestock systems of the highlands. The feed industry is developing rapidly to support the country\'s ambitious plans for livestock sector modernization under the Livestock Master Plan (LMP). Commercial feed mills have emerged in Addis Ababa, Debre Zeit, Hawassa, and other urban centers, producing feeds primarily for the growing dairy, poultry, and urban/peri-urban livestock fattening enterprises. Despite the large livestock population, most animals are fed on natural pastures and crop residues, with productivity per animal remaining very low. The government has established feed quality standards through the Ethiopian Standards Agency and supports improved forage development through the Ethiopian Institute of Agricultural Research (EIAR).',
    ingredients: 'Ethiopia offers diverse locally available feed ingredients that vary significantly by region and season. Noug (niger seed) cake is a uniquely Ethiopian protein source, widely available and commonly used in dairy and fattening rations in the highlands. Linseed (flax) cake is another traditional Ethiopian oilseed byproduct used in cattle feeding. Wheat bran and wheat middlings from the country\'s extensive wheat milling industry provide affordable energy and moderate protein. Teff straw, the residue from Ethiopia\'s signature grain, is the most abundant crop residue but has low nutritive value without treatment. Maize stover and sorghum stover are important roughage sources in the lowlands and mid-altitudes. Brewers\' spent grain from the beer industry (BGI, Meta Abo, Habesha breweries) is a popular and cost-effective protein supplement for urban and peri-urban dairy cows. Molasses from sugar factories (Wonji, Metahara, Finchaa) serves as an energy supplement and palatability enhancer. For improved forages, Desmodium, Rhodes grass, Brachiaria, and oats/vetch mixtures are promoted by EIAR and the International Livestock Research Institute (ILRI). Atella, the byproduct from traditional tella and areke brewing, is widely used as a protein supplement for dairy cows in smallholder systems.',
    cost: 'Feed scarcity and cost are the primary constraints to livestock productivity in Ethiopia, with dramatic seasonal price swings between the post-harvest period (November to January) and the pre-harvest dry season (April to June). Noug cake, the most common protein supplement, can double in price between wet and dry seasons. Farmers can manage costs by purchasing and storing concentrate ingredients immediately after harvest when prices are lowest, establishing improved forage plots on field boundaries and under-utilized land, and properly conserving crop residues (hay-making and silage production). The concentration of feed mills around Addis Ababa and major cities means that rural livestock producers face higher feed costs due to transport margins. Cooperative dairy unions (such as Selale, Sebeta, Ada\'a) help members access bulk feed ingredients at negotiated prices. The government encourages community-level feed processing through the provision of feed chopping and mixing equipment to farmer groups. For pastoral areas, the establishment of hay production sites along major rivers and in strategic locations provides emergency dry-season feed reserves. Purchasing from local oilseed processors and flour mills directly, rather than through intermediaries, can save 15 to 25% on ingredient costs.'
  },
  ghana: {
    name: 'Ghana',
    overview: 'Ghana\'s livestock sector includes cattle (predominantly in the northern regions), sheep and goats (nationwide), pigs, and a rapidly expanding poultry industry. The country imports a significant portion of its meat requirements, particularly poultry, creating strong market incentives for domestic production expansion. The commercial poultry sector is concentrated around Accra, Kumasi, Tema, and Dormaa-Ahenkro, with several large-scale operations including Darko Farms, Akate Farms, and Boris Poultry. The feed industry has grown alongside the poultry sector, with commercial feed mills including GAFCO, Agricare, and several smaller operators producing compound feeds. Small ruminant production is important for household food security and income, particularly in the Guinea savanna of the north. The government\'s Rearing for Food and Jobs (RFJ) initiative complements the PFJ crop program by supporting livestock development, including improved feed access.',
    ingredients: 'Ghana\'s feed ingredient supply draws on the country\'s diverse agricultural production. Maize is the primary energy source in commercial feeds, produced across the country but particularly in the Brong-Ahafo, Ashanti, and Northern regions. Soybean meal is increasingly available as soybean cultivation expands in the Northern, Upper East, and Volta regions, though imports still supplement domestic supply. Groundnut cake from the northern groundnut belt is a traditional protein supplement for ruminants. Copra cake from coconut processing in the coastal regions provides an economical feed ingredient. Palm kernel cake from the oil palm industry in the Ashanti, Eastern, and Western regions is a widely used, affordable energy and fiber source for ruminants and pigs. Wheat bran from flour mills in Tema provides an accessible energy and protein supplement. For ruminants, Guinea grass (Panicum maximum) and Stylosanthes guianensis are the most promoted improved forages, while natural savanna pastures of Andropogon and Hyparrhenia grasses provide the grazing base in the north. Cowpea and groundnut haulms are valuable crop residues for dry season feeding of small ruminants. Brewery waste from Accra Brewery and Guinness Ghana is a sought-after dairy feed ingredient in the Greater Accra region.',
    cost: 'Feed costs are the biggest challenge facing Ghana\'s livestock sector, particularly the poultry industry, where feed represents 65 to 70% of total production costs. Maize prices follow strong seasonal patterns, with lowest prices during the major season harvest (August to October) and highest prices during the lean season (March to June), with swings of 30 to 50% being common. Poultry and pig farmers can significantly reduce costs by establishing bulk storage facilities to purchase maize at harvest prices for year-round use. Palm kernel cake and copra cake offer cost-effective alternatives that can partially replace more expensive soybean meal in ruminant and pig diets. For small ruminant farmers in the north, the strategic cultivation of fodder banks using Stylosanthes and Leucaena, combined with proper conservation of crop residues through improved storage, can dramatically reduce dry-season feeding costs. Major feed ingredient markets include Agbogbloshie and Ashaiman in the Greater Accra region, Kumasi central market, and Tamale market in the north. Farmers can save 10 to 20% by purchasing through cooperatives or directly from farming communities rather than through urban market intermediaries. The Livestock and Poultry Farmers Association of Ghana (LIPFAG) advocates for policy measures to reduce feed costs, including reduced import duties on raw materials not produced domestically.'
  },
  kenya: {
    name: 'Kenya',
    overview: 'Kenya has one of East Africa\'s most developed livestock sectors, with dairy, poultry, beef, and small ruminant production contributing significantly to the economy and food security. The dairy industry is particularly important, with Kenya being one of Africa\'s largest milk producers, centered in the Rift Valley (Nyandarua, Nakuru, Uasin Gishu) and Central (Kiambu, Murang\'a) regions. The poultry sector includes both indigenous birds and a growing commercial layer and broiler industry. The commercial feed milling industry is well-established, with major producers including Unga Group, Pembe Flour Mills (Sigma Feeds), Athi River Mining (feed division), and numerous smaller millers across the country. Kenya\'s pastoral regions (northeastern counties, parts of Rift Valley, and the coast) support large populations of cattle, sheep, goats, and camels. The Kenya Dairy Board and the Kenya Poultry Farmers Association support industry development and quality standards.',
    ingredients: 'Kenya offers a diverse range of locally available feed ingredients suited to its varied livestock systems. Maize (and maize germ from milling) is the primary energy source for commercial feeds, though local production often falls short of demand, requiring imports. Wheat bran and wheat pollard from the extensive milling industry are widely used energy and protein sources for dairy cattle across the highlands. Cottonseed cake from Coast and Eastern Province cotton gins provides affordable protein for ruminants. Sunflower cake from the Nakuru and Trans-Nzoia regions is an increasingly important protein source. Soybean meal is partially produced domestically but largely imported. Omena (silver cyprinid fish) from Lake Victoria is dried and used as a protein source in poultry feeds, though prices have risen considerably. Napier grass (Pennisetum purpureum) is the backbone of Kenya\'s smallholder dairy feeding system, grown on field boundaries and as dedicated fodder plots in the highlands. Rhodes grass (Chloris gayana) is cultivated commercially and sold as hay, particularly from the Naivasha, Athi River, and Laikipia areas. Desmodium (silverleaf) serves as both a high-protein leguminous forage and a companion planting crop. Lucerne (alfalfa) is grown under irrigation in Laikipia and parts of the Rift Valley, providing premium quality forage. Dairy meal, a commercially produced compound concentrate, is widely available and used by smallholder dairy farmers across the highlands.',
    cost: 'Feed costs are the dominant operational expense in Kenyan livestock production, accounting for approximately 60 to 70% of dairy production costs and up to 75% of poultry production costs. Dairy farmers in the highlands face the highest feed costs during the dry seasons (January to March and July to September) when Napier grass growth slows and they must purchase supplementary feeds. Dairy meal prices vary from KES 1,800 to 2,500 per 70 kg bag depending on brand, composition, and season. Farmers can reduce costs by growing adequate Napier grass and conserving it as silage during peak growth periods, using total mixed ration (TMR) approaches that maximize utilization of cheaper local ingredients, and purchasing concentrate ingredients (wheat bran, maize germ, cottonseed cake) directly from processors rather than through dealers. Rhodes grass hay, delivered from commercial hay producers in the Rift Valley, typically costs KES 350 to 500 per bale (15 kg) and is an essential dry-season supplement. Poultry farmers benefit from joining Sacco-style purchasing groups to buy maize and other ingredients at harvest-time prices for bulk storage. The Kenya Agricultural and Livestock Research Organization (KALRO) provides feed formulation advice, and county-level livestock extension officers can help farmers develop cost-effective feeding programs using locally available ingredients.'
  },
  morocco: {
    name: 'Morocco',
    overview: 'Morocco\'s livestock sector is a vital component of the agricultural economy, with cattle, sheep, goats, and poultry production spread across the country\'s diverse agroecological zones. The country has approximately 3.5 million cattle, 22 million sheep, and 6 million goats, and a highly developed poultry industry producing over 700,000 tonnes of white meat annually. The dairy sector, centered in the Gharb, Doukkala, Chaouia, and Tadla regions, produces over 2.5 billion liters of milk annually. Morocco\'s feed industry is one of the most developed in Africa, with over 100 licensed feed mills producing compound feeds, led by companies including Alf Sahel, Cicalim, and Afriquia Gaz Animal Feed Division. The Plan Generation Green emphasizes livestock value chain development, including improved feeding practices and domestic feed ingredient production. The traditional pastoral system in the eastern and southern regions faces challenges from drought and rangeland degradation.',
    ingredients: 'Morocco benefits from a diverse feed ingredient base combining domestic production with strategic imports. Barley is the traditional and most widely used grain for livestock in Morocco, grown extensively in the rainfed areas of the Chaouia, Saiss, and eastern regions. Wheat bran from the country\'s extensive wheat milling industry is one of the most commonly used dairy and sheep feed ingredients. Sugar beet pulp from Morocco\'s sugar industry (COSUMAR) provides a valuable energy-rich byproduct for dairy cattle rations. Sunflower meal from the domestic oilseed industry offers protein supplementation. Imported soybean meal is the primary protein source for the poultry industry. Olive cake (grignon) from Morocco\'s large olive oil industry is used as a low-cost roughage supplement for sheep and cattle, though it requires careful inclusion rate management. Alfalfa (lucerne) is grown under irrigation, particularly in the Tadla, Souss, and Haouz regions, providing premium quality forage. Maize silage is increasingly adopted by modern dairy farms. Cactus pads (Opuntia) serve as a drought-resilient feed source in the semi-arid zones, providing water and energy to small ruminants. Cereal stubble grazing after harvest is a traditional and economically important feed resource across the major grain-producing plains.',
    cost: 'Feed costs in Morocco\'s livestock sector are significantly impacted by the country\'s variable rainfall patterns, which create pronounced inter-annual variation in domestic barley and forage production. In drought years, barley prices can double or triple, and the government typically responds by reducing or eliminating import duties on animal feed ingredients. Farmers can manage costs by establishing on-farm reserves of barley and hay during good production years, investing in alfalfa and improved pasture establishment for long-term forage security, and using industrial byproducts (sugar beet pulp, olive cake, wheat bran) that have more stable pricing than grain. The government provides drought relief support including subsidized barley imports and feed distribution through regional agriculture offices during severe drought events. Feed ingredient markets operate in all major cities, with Casablanca, Fes, and Meknes being particularly important trading centers. Cooperative purchasing through COPAG and other dairy cooperatives helps smallholder dairy farmers access compound feeds at negotiated prices. The National Federation of Breeders and Livestock Producers (FIVIAR) advocates for policies to stabilize feed costs, including strategic grain reserves and favorable import tariff regimes during drought periods.'
  },
  nigeria: {
    name: 'Nigeria',
    overview: 'Nigeria is home to Africa\'s largest human population and one of its most significant livestock sectors, with approximately 20 million cattle, 44 million goats, 42 million sheep, and a massive poultry industry. The northern states (Kano, Kaduna, Sokoto, Borno, Adamawa) support the majority of ruminant livestock, while poultry and pig production are concentrated in the south-west (Lagos, Oyo, Ogun) and middle belt (Plateau, Nassarawa). The poultry industry alone consumes over 3 million tonnes of feed annually, making Nigeria one of Africa\'s largest feed markets. Major commercial feed mills include Flour Mills of Nigeria (Premier Feeds), Vital Feeds, Animal Care, CHI Foods (Olam), Hybrid Feeds, and numerous regional operators. The sector faces challenges including high feed ingredient costs, the farmer-herder conflict affecting pastoralism, and competition between food and feed uses of crops. The livestock sector is a priority area under the National Agricultural Development Strategy.',
    ingredients: 'Nigeria has a rich diversity of locally available feed ingredients spanning its varied agroecological zones. Maize is the primary energy source for poultry and pig feeds, produced extensively in the north-central and north-west states, though domestic demand often exceeds supply. Soybean meal, produced mainly in Benue, Kaduna, and Niger states, is the principal protein source for monogastric feeds. Groundnut cake (kulikuli residue) from the northern groundnut belt is a traditional and widely used protein source for all livestock types. Cottonseed cake from the cotton-producing states (Zamfara, Katsina, Gombe) provides affordable protein for ruminants. Brewers\' dried grain (BDG) from Nigerian Breweries, International Breweries, and smaller operators is a popular and nutritious dairy and beef cattle supplement. Palm kernel cake (PKC) from the oil palm industry in the south-east and south-south zones is a cheap and abundant feed ingredient. Cassava peels and chips, dried and processed, serve as a maize replacement in poultry and pig diets (up to 20-30% inclusion). Cowpea haulms and groundnut haulms are critical dry-season feeds for cattle and small ruminants in the north. Gamba grass and Guinea grass serve as the primary forages for intensive ruminant operations. Fish meal from the artisanal and industrial fisheries provides essential amino acids for poultry and aquaculture feeds.',
    cost: 'Feed costs are the single largest challenge facing Nigerian livestock producers, representing 65 to 75% of total production costs for poultry and 50 to 60% for ruminant operations. Maize prices exhibit extreme volatility, driven by seasonal supply fluctuations, currency movements affecting import costs, and competition from the human food and industrial sectors. The naira\'s depreciation has made imported soybean meal and other ingredients increasingly expensive, pushing farmers toward greater use of local alternatives. Key cost-saving strategies include purchasing maize and soybean directly from farmers or cooperatives in producing states (Kaduna, Benue, Niger) during the post-harvest period (October to December), substituting expensive imported fish meal with locally produced alternatives or insect meal (black soldier fly larvae), and maximizing inclusion of cheap local ingredients like PKC, cassava meal, and cottonseed cake. Ruminant farmers in the north can reduce costs by establishing improved pastures of Brachiaria and Panicum, conserving crop residues as hay, and developing agro-pastoral partnerships with crop farmers for access to crop aftermath and residues. Major feed ingredient markets include Dawanau in Kano (Africa\'s largest grain market), Mile 12 in Lagos, and Sabo/Kaduna central market. Joining poultry farmer associations or feed buying cooperatives can save 15 to 25% through bulk purchasing power.'
  },
  rwanda: {
    name: 'Rwanda',
    overview: 'Rwanda\'s livestock sector has recovered substantially from the 1994 genocide, with the government implementing ambitious programs to rebuild the national herd and improve livestock productivity. The Girinka ("One Cow per Poor Family") program has distributed over 400,000 dairy cows to poor households, significantly increasing both milk production and the demand for improved animal feeding. The country has approximately 1.3 million cattle, 3 million goats, 1.5 million sheep, and a growing poultry sector. The small national territory and high population density mean that intensive, stall-fed livestock systems are increasingly necessary. The commercial feed industry is developing, with feed mills in Kigali and other cities producing dairy concentrate, poultry feed, and pig feed. The Rwanda Agriculture Board (RAB) promotes improved feeding technologies and forage development as key pillars of livestock sector transformation.',
    ingredients: 'Rwanda\'s hilly terrain and small farm sizes shape the available feed ingredients. Napier grass (Pennisetum purpureum) is the most widely grown forage crop, cultivated on field boundaries, contour strips, and terraces, serving as the backbone of smallholder dairy feeding. Desmodium and Calliandra calothyrsus are promoted as protein-rich leguminous forages that can be intercropped with Napier grass or established as dedicated fodder banks on hillsides. Maize bran from local mills provides energy supplementation for dairy cows. Wheat bran is available from the Minimex and Sosoma flour mills. Soybean meal and soybean cake from expanding domestic soybean production offer growing protein supply for commercial feeds. Dried banana pseudo-stems and banana leaves, abundantly available in the banana-growing zones, serve as supplementary roughage. Rice bran from rice mills in the Bugesera and eastern marshlands provides an affordable energy source. Brewery waste from Bralirwa (Heineken) and Skol Rwanda is distributed to peri-urban dairy farmers in the Kigali area as a valuable protein supplement. Sweet potato vines, harvested from the country\'s extensive sweet potato cultivation, provide excellent quality forage for both cattle and small ruminants.',
    cost: 'Feed costs are the primary constraint to livestock productivity in Rwanda, with the limited availability of grazing land making smallholder dairy farmers particularly dependent on purchased or cultivated feed. Napier grass establishment is the most cost-effective long-term feeding strategy, but initial planting material and the 3 to 4 month establishment period require upfront investment. Concentrate ingredients (maize bran, wheat bran, soybean cake) are available from agro-dealers and feed suppliers in Kigali, Musanze, and Huye, but prices are elevated by Rwanda\'s landlocked position and high transport costs from the coast. Seasonal price variation is less extreme in Rwanda than in many African countries due to the bimodal rainfall supporting two growing seasons, but dry season (June to September) feed prices are typically 20 to 30% higher. Cost-saving approaches include maximizing Napier grass productivity through regular cutting, manure application, and proper management; intercropping with Desmodium to eliminate the need for purchased protein feeds; forming dairy cooperative groups (such as through RDFA) to purchase concentrates in bulk; and utilizing free or low-cost byproducts like banana pseudo-stems and sweet potato vines. RAB extension workers provide free advice on feed formulation and forage establishment adapted to each agroecological zone.'
  },
  senegal: {
    name: 'Senegal',
    overview: 'Senegal\'s livestock sector is a crucial component of the rural economy, with the Sahelian and Sudano-Sahelian pastoral systems in the north and east supporting large herds of Zebu cattle, Sahelian sheep (including the prized Ladoum breed), and goats. The peri-urban dairy industry around Dakar, Thies, and Saint-Louis is growing, driven by the Laiterie du Berger and other processing companies. The poultry sector has expanded significantly, with domestic production increasingly replacing imports, supported by modern feed mills including SEDIMA, NMA Sanders, and AVISEN. The pastoral Fulani communities practice transhumance across the northern and eastern regions, moving herds to follow seasonal pasture availability. The government\'s Programme National de Developpement de l\'Elevage (PNDE) prioritizes improved feeding, breed improvement, and value chain development.',
    ingredients: 'Senegal\'s feed ingredient supply reflects its agro-pastoral economy and Sahelian ecology. Groundnut haulms (fane d\'arachide) are the most important and widely used dry season feed for ruminants, harvested and stored after the groundnut season. Groundnut cake (tourteau d\'arachide) from the groundnut oil industry provides a readily available protein supplement. Cottonseed cake from SODEFITEX\'s cotton processing is used in ruminant feeding in the Kolda and Tambacounda regions. Millet and sorghum bran from local cereal processing provide energy supplementation. Rice bran from the rice mills of the Senegal River Valley (SAED zone) is an increasingly available and affordable feed ingredient. For the poultry industry, maize is imported or sourced from the southern Casamance region, and soybean meal is largely imported through the port of Dakar. Fish meal from Senegal\'s important artisanal and industrial fisheries provides high-quality protein for poultry and aquaculture feeds. Natural rangelands of annual grasses (Cenchrus biflorus, Schoenefeldia gracilis) provide seasonal grazing, with planted Andropogon gayanus and Panicum maximum pastures promoted for intensive operations. Acacia albida (Faidherbia) pods, which fall during the dry season when other feed is scarce, provide a valuable natural supplement in the agro-pastoral zones.',
    cost: 'Feed costs in Senegal exhibit extreme seasonal variation, particularly for ruminant producers in the pastoral and agro-pastoral zones. The dry season (November to June) is the critical period when natural pastures are depleted and groundnut haulm prices can increase by 100 to 200% compared to immediate post-harvest prices (October to November). Strategic purchasing and storage of groundnut haulms immediately after the groundnut harvest is the most effective cost-saving measure for ruminant farmers. For the peri-urban dairy sector, LAITERIE DU BERGER and similar companies facilitate feed access for their contracted dairy farmers. Commercial poultry feed prices are relatively stable due to the organized supply chains of major mills, but small-scale producers face higher per-unit costs when purchasing from retail outlets. The government provides subsidized feed during drought emergencies through the Commissariat a la Securite Alimentaire (CSA), distributing aliment betail (livestock feed concentrates) through regional livestock services. Farmer cooperatives and Groupements d\'Interet Economique (GIE) can negotiate better prices for bulk feed purchases. Markets in Dakar (Pikine, Rufisque), Thies, Kaolack (a major groundnut trading center), and Tambacounda are the primary commercial sources for feed ingredients. The development of cultivated forage production, including irrigated Brachiaria and Panicum pastures, is increasingly promoted as a business opportunity for farmers with access to water resources.'
  },
  'south-africa': {
    name: 'South Africa',
    overview: 'South Africa has the most developed and industrialized livestock and feed sector on the African continent. The country\'s livestock industry encompasses large-scale commercial beef cattle (approximately 14 million head), dairy (over 1.5 million dairy cows producing 3.5 billion liters annually), sheep and wool production (over 20 million sheep), pigs (over 1.5 million), and one of the world\'s largest broiler chicken industries (producing over 1.8 billion birds annually). The animal feed industry is a major economic sector, with total feed production exceeding 12 million tonnes annually. Major feed companies include Astral Foods (Meadow Feeds), RCL Foods (Epol and Molatek), AFGRI Animal Feeds, De Heus South Africa, and Nutri Feeds. The industry is regulated by the Fertilizers, Farm Feeds, Agricultural Remedies and Stock Remedies Act (Act 36 of 1947) and overseen by the Department of Agriculture. The Animal Feed Manufacturers Association (AFMA) represents the commercial feed industry.',
    ingredients: 'South Africa produces and uses a wide range of feed ingredients at a scale unmatched elsewhere in Africa. Yellow maize is the primary energy source, with domestic production of 12 to 16 million tonnes annually (depending on rainfall), making South Africa typically a net maize exporter. Soybean meal is the principal protein source for monogastric feeds, with domestic soybean crushing capacity expanding rapidly. Sunflower oilcake from the significant domestic sunflower industry (North West, Free State, Limpopo provinces) provides an alternative protein source. Lucerne (alfalfa) is the premium roughage for dairy cattle, produced commercially under irrigation in the Western Cape, Northern Cape, and Free State. Maize silage is the most important conserved forage on commercial dairy farms, with silage production technology well-established. Hominy chop (maize byproduct from de-germing) is a widely used energy source for dairy and beef cattle. Wheat bran from the milling industry supplements dairy rations. Cottonseed oilcake from the Limpopo and KwaZulu-Natal cotton industry provides protein for ruminants. Fishmeal from the West Coast pelagic fishery is a premium ingredient for poultry and aquaculture. Molasses from the KwaZulu-Natal sugar industry is used in liquid feed supplements and silage additives. Eragrostis (teff) hay is the most widely traded roughage for horses and cattle across the Highveld.',
    cost: 'Feed costs in South Africa are driven primarily by the maize price (SAFEX white and yellow maize prices), soybean meal prices, and roughage costs, which together represent the bulk of livestock feeding expenditure. Maize prices are influenced by domestic rainfall patterns, SAFEX futures market dynamics, and the rand-dollar exchange rate affecting export and import parity pricing. Dairy farmers typically spend R2,000 to R4,500 per cow per month on feed, depending on production level and feeding system. Commercial broiler operations target feed costs of R4,500 to R5,500 per tonne for grower feeds. Strategies for managing feed costs include forward contracting of maize and soybean through the SAFEX market to lock in favorable prices, on-farm grain and silage production to reduce purchased feed dependency, precision feeding using TMR (total mixed ration) systems to minimize waste, and regular feed efficiency monitoring through production records. Roughage costs can be managed by establishing and maintaining productive cultivated pastures (ryegrass, kikuyu, lucerne) appropriate to the region. Feed ingredients are sourced through AFGRI, Senwes, VKB, NWK, and other agribusiness cooperatives, as well as independent feed brokers. Emerging and smallholder farmers can access support through the Department of Agriculture\'s extension services and farmer development programs. AFMA publishes regular market reports on feed ingredient prices, providing valuable information for purchasing decisions.'
  },
  tanzania: {
    name: 'Tanzania',
    overview: 'Tanzania has one of East Africa\'s largest livestock populations, with over 30 million cattle (primarily Zebu breeds in traditional pastoral systems), 18 million goats, 5 million sheep, and a growing commercial poultry sector. The livestock sector contributes approximately 7% of GDP, with pastoral communities in the Maasai Steppe, Sukumaland, and other semi-arid zones managing the majority of cattle. The dairy industry, centered in the Kilimanjaro, Arusha, Tanga, and Iringa regions, is growing with the expansion of smallholder dairy farming using crossbred cattle. The commercial feed industry is developing, with feed mills in Dar es Salaam, Arusha, and Iringa producing poultry, dairy, and pig feeds. Companies including Tanfeed, Silverlands Tanzania, and several smaller operators serve the commercial market. The Tanzania Livestock Research Institute (TALIRI) and Sokoine University of Agriculture (SUA) provide research and extension support for improved animal nutrition.',
    ingredients: 'Tanzania\'s diverse agro-climatic zones offer varied feed ingredients. Maize bran and broken maize from the country\'s milling industry provide the primary energy base for commercial feeds and smallholder supplementation. Sunflower cake from the expanding sunflower production in the Singida, Dodoma, and Iringa regions is an important and increasingly available protein source for both ruminants and monogastric animals. Cottonseed cake from the cotton ginneries of the Lake Zone (Mwanza, Shinyanga) provides affordable protein for cattle and small ruminants. Soybean meal production is growing, with soybean cultivation expanding in the Southern Highlands. Rice bran from the Mbeya, Morogoro, and Shinyanga rice mills is a cheap energy supplement. Copra cake from coconut processing in the Pwani and Tanga coastal regions provides an economical ingredient. For ruminants, Brachiaria and Guinea grass (Panicum maximum) are promoted as improved forages, while natural miombo woodland and savanna grasslands provide the extensive grazing base. Leucaena and Gliricidia fodder trees are promoted for the dairy sector. Sisal waste (from the Tanga sisal industry) has been explored as a roughage source. Molasses from the Kilombero and Mtibwa sugar estates serves as an energy supplement and silage additive.',
    cost: 'Feed costs represent the major bottleneck for Tanzania\'s livestock sector development, with most commercial operations spending 60 to 70% of their operational budget on feed. Seasonal price variations for maize and other ingredients can be extreme, with prices in the Dar es Salaam market rising by 40 to 60% between the post-harvest period (July to September) and the pre-harvest lean season (January to March). Sunflower cake prices are generally more stable and represent a cost-effective protein option compared to imported soybean meal. For dairy farmers in the highlands, establishing improved pastures of Brachiaria, Chloris gayana (Rhodes grass), and forage legumes can reduce the need for expensive purchased concentrates. Smallholder dairy farmers in the Kilimanjaro and Arusha regions benefit from established supply chains for dairy concentrates through cooperative networks like TDCU and KNCU. Pastoral and agro-pastoral livestock keepers can improve dry-season feeding economics by conserving hay during the wet season and strategically supplementing with cottonseed cake and mineral licks from June to October. Major feed ingredient markets operate in Dar es Salaam (Kariakoo and Tandale markets), Arusha, Mwanza, and Mbeya. Cooperative purchasing through livestock keeper associations and dairy cooperatives helps reduce per-unit costs, and the Tanzanian livestock ministry promotes village-level feed processing centers equipped with simple chopping and mixing equipment.'
  },
  tunisia: {
    name: 'Tunisia',
    overview: 'Tunisia\'s livestock sector is centered on dairy cattle (approximately 700,000 head), sheep (over 7 million, including the famous Queue Fine de l\'Ouest breed), goats (1.5 million), and a modern poultry industry. The dairy sector is concentrated in the northern regions (Beja, Jendouba, Bizerte, Ariana) where rainfall and forage conditions are favorable, producing approximately 1.4 billion liters of milk annually. The sheep sector is economically and culturally important, with the Eid al-Adha (Eid el-Kebir) festival creating a major seasonal demand spike. Tunisia\'s feed industry is well-developed, with over 200 licensed feed mills producing compound feeds, overseen by the Office de l\'Elevage et des Paturages (OEP) and the Groupement Interprofessionnel des Viandes Rouges et du Lait (GIVLait). The country imports significant quantities of feed ingredients, particularly soybeans, maize, and barley, making the sector sensitive to international market fluctuations.',
    ingredients: 'Tunisia\'s feed ingredient supply combines domestic forage and grain production with significant imports. Barley is the traditional and most widely used feed grain, grown in the semi-arid central and southern regions and supplemented by imports during drought years. Wheat bran and wheat middlings from the country\'s extensive milling industry are among the most commonly used concentrate ingredients for dairy cattle and sheep. Soybean meal is imported and used extensively in poultry and dairy concentrate feeds. Olive cake (grignon d\'olive) from Tunisia\'s large olive oil industry is used as a low-cost roughage and energy supplement for sheep and cattle, particularly during the dry season. Sugar beet pulp from the domestic sugar industry provides valuable fiber and energy for dairy rations. Oat and triticale forages, grown during winter, provide high-quality green feed for dairy cattle in the north. Sulla (Hedysarum coronarium) is a unique Mediterranean legume forage widely cultivated in the Tell region, providing excellent quality hay and green feed. Cactus pads (Opuntia ficus-indica) are extensively used as a drought-resilient feed source for sheep in the central and southern semi-arid zones, providing both energy and water during dry periods. Concentrated feed blocks (aliments de betail) containing barley, wheat bran, and mineral supplements are commercially produced and widely used for sheep supplementation.',
    cost: 'Feed costs in Tunisia are heavily influenced by rainfall patterns and international grain prices, with drought years causing dramatic increases in both domestic grain prices and demand for imported feed ingredients. The government plays an active role in stabilizing feed costs through the Office des Cereales, which manages strategic grain reserves and regulates barley and wheat bran prices. During drought emergencies, the government subsidizes barley imports and distributes subsidized feed concentrates through regional OEP offices and the network of private feed dealers. Sheep fattening for Eid al-Adha creates a seasonal demand peak in feed ingredients during the months preceding the festival, typically pushing prices higher. Dairy farmers benefit from the relatively stable pricing of commercial compound feeds produced by major feed companies. Cost-saving strategies include cultivating winter forages (oats, sulla, vetch) to reduce purchased concentrate requirements during the October-to-May growing season, utilizing olive cake and cactus during the summer dry period, and purchasing barley and other grains during the post-harvest period (June to July) for storage. Feed ingredients are traded through the central market system in Tunis and regional markets in Sousse, Sfax, and Beja. The UTAP (Union Tunisienne de l\'Agriculture et de la Peche) farmers\' union negotiates collective purchasing arrangements for its members, and dairy cooperatives facilitate access to compound feeds at negotiated prices.'
  },
  uganda: {
    name: 'Uganda',
    overview: 'Uganda\'s livestock sector is growing rapidly, supporting approximately 15 million cattle, 16 million goats, 4 million sheep, and an expanding commercial poultry industry. The cattle corridor running from the southwest (Ankole) through central Uganda to the northeast (Karamoja) supports the majority of cattle, with the south-western Ankole-Watusi and central Friesian-cross dairy herds being particularly important for milk production. Uganda produces approximately 2.5 billion liters of milk annually, making it one of East Africa\'s largest dairy producers. The commercial feed industry is developing around Kampala, Jinja, Mbarara, and other urban centers, with companies including Ugachick, Biyinzika, and Nsindika Group producing compound feeds primarily for poultry. The Uganda National Bureau of Standards (UNBS) has established feed quality standards, and the Uganda Veterinary Association provides industry guidance. The government\'s Agriculture Sector Strategic Plan includes livestock sector development as a priority.',
    ingredients: 'Uganda benefits from a relatively favorable feed ingredient environment due to its generally adequate rainfall and diverse agricultural production. Maize bran and broken maize from local milling operations are the primary energy sources for commercial feeds and smallholder supplementation. Soybean meal production is increasing, with soybean cultivation expanding in the eastern (Iganga, Tororo) and northern (Lira, Gulu) regions. Sunflower cake from the Lira and Soroti areas provides an affordable protein option. Cottonseed cake from the cotton industry in the northern and eastern regions supplements ruminant diets. Fish meal from Lake Victoria\'s Nile perch and tilapia processing industry is an important poultry feed ingredient, though declining fish stocks have raised prices. Brewers\' spent grain from Nile Breweries and Uganda Breweries is distributed to peri-urban dairy farmers as a valuable supplement. For dairy cattle, Napier grass (elephant grass) is the foundation of feeding systems in the southwest and central regions, with cutting intervals of 6 to 8 weeks providing regular fresh feed. Chloris gayana (Rhodes grass) is cultivated in the cattle corridor for hay production. Calliandra calothyrsus and Sesbania sesban fodder trees are promoted by NARO and development organizations as protein-rich supplements for dairy cows in the highlands. Banana peels and pseudo-stems from Uganda\'s extensive banana production are used as supplementary feeds for cattle and goats.',
    cost: 'Feed costs are a major constraint for Ugandan livestock producers, with purchased feeds representing 50 to 65% of dairy production costs and up to 70% for commercial poultry operations. Maize prices show significant seasonal variation, with the lowest prices during the main harvest (December to January) and the highest during the planting season (March to May). Dairy farmers can minimize costs by maintaining productive Napier grass stands (which can support 2 to 3 cows per acre when well-managed), supplementing with local byproducts like banana residues and Calliandra browse rather than purchasing expensive commercial dairy meal. The establishment of small-scale feed mixing operations at the farm or cooperative level can reduce costs by 20 to 30% compared to purchasing commercial compound feeds. Poultry farmers benefit from joining the Uganda Poultry Farmers Network to share information on ingredient sourcing and pricing. Feed ingredients are sourced from Kisenyi and Owino markets in Kampala, as well as from regional markets in Jinja, Mbarara, and Gulu. Direct purchasing from grain traders in producing areas (Masindi, Iganga, Lira) during harvest time offers significant savings over urban market prices. NARO and the Dairy Development Authority provide extension advice on cost-effective feeding strategies, and several NGOs including Heifer International and Send a Cow support improved dairy feeding through forage development programs.'
  }
};

let modified = 0;

for (const [slug, info] of Object.entries(DATA)) {
  const filePath = path.join(DIR, slug + '.html');
  if (!fs.existsSync(filePath)) {
    console.log(`SKIP (not found): ${slug}.html`);
    continue;
  }

  let html = fs.readFileSync(filePath, 'utf8');

  // Check if content already added
  if (html.includes('class="seo-content"')) {
    console.log(`SKIP (already has seo-content): ${slug}.html`);
    continue;
  }

  const seoBlock = `
<section class="seo-content" style="max-width:800px;margin:2rem auto;padding:0 1rem;">
<h2 style="font-size:1.15rem;font-weight:700;color:#1e293b;margin:1.5rem 0 0.5rem;">Livestock Feed in ${info.name}</h2>
<p style="font-size:0.92rem;line-height:1.7;color:#6B7280;">${info.overview}</p>

<h2 style="font-size:1.15rem;font-weight:700;color:#1e293b;margin:1.5rem 0 0.5rem;">Common Local Feed Ingredients</h2>
<p style="font-size:0.92rem;line-height:1.7;color:#6B7280;">${info.ingredients}</p>

<h2 style="font-size:1.15rem;font-weight:700;color:#1e293b;margin:1.5rem 0 0.5rem;">Feed Cost &amp; Sourcing Tips</h2>
<p style="font-size:0.92rem;line-height:1.7;color:#6B7280;">${info.cost}</p>
</section>
`;

  // Insert after </main> and before <afro-footer>
  const insertPoint = html.indexOf('</main>');
  if (insertPoint === -1) {
    console.log(`SKIP (no </main> found): ${slug}.html`);
    continue;
  }

  const afterMain = insertPoint + '</main>'.length;
  html = html.slice(0, afterMain) + '\n' + seoBlock + '\n' + html.slice(afterMain);

  fs.writeFileSync(filePath, html, 'utf8');
  modified++;
  console.log(`DONE: ${slug}.html`);
}

console.log(`\nTotal livestock feed pages modified: ${modified}`);
